export interface SpanBackend {
  write(span: CognitionSpan): Promise<void>;
  /** Read all spans for a trace. */
  loadTrace(trace_id: string): Promise<CognitionSpan[]>;
  /** For tests. */
  __reset?(): void;
}

class MemoryBackend implements SpanBackend {
  private buffer: CognitionSpan[] = [];
  private readonly cap = 10_000;
  async write(span: CognitionSpan): Promise<void> {
    this.buffer.push(span);
    if (this.buffer.length > this.cap) {
      this.buffer.splice(0, this.buffer.length - this.cap);
    }
  }
  async loadTrace(trace_id: string): Promise<CognitionSpan[]> {
    return this.buffer.filter(s => s.trace_id === trace_id).sort((a, b) => a.started_at - b.started_at);
  }
  __reset(): void { this.buffer = []; }
}

