/**
 * Persist a cognition span. Never throws — failures are logged and counted.
 * The span_id is generated here so callers don't have to reach for randomUUID.
 */
export async function writeSpan(init: SpanInit): Promise<string> {
  const now = Date.now();
  const span: CognitionSpan = {
    span_id: randomUUID(),
    trace_id: init.trace_id,
    parent_span_id: init.parent_span_id ?? null,
    workflow: init.workflow,
    step: init.step,
    kind: init.kind,
    prompt: init.prompt ?? null,
    model: init.model ?? null,
    provider: init.provider ?? null,
    input_redacted: init.input === undefined ? null : redactValue(init.input, init.input_entity_hint),
    output_redacted: init.output === undefined ? null : redactValue(init.output, init.output_entity_hint),
    validate_result: init.validate_result ?? null,
    confidence: init.confidence ?? null,
    prompt_tokens: init.prompt_tokens ?? null,
    completion_tokens: init.completion_tokens ?? null,
    cost_usd: init.cost_usd ?? null,
    latency_ms: init.latency_ms,
    cache_hit: init.cache_hit ?? false,
    status: init.status,
    error_code: init.error_code ?? null,
    metadata: init.metadata ?? {},
    started_at: now - init.latency_ms,
    finished_at: now,
  };
  try {
    await __backend.write(span);
    counter("cognition.span_written", { kind: init.kind, status: init.status });
  } catch (e) {
    counter("cognition.span_write_failed");
    const msg = e instanceof Error ? e.message : String(e);
    logger.warn("cognition_span_write_failed", { event: "traces", status: "rejected", trace_id: span.trace_id, metadata: { error: msg.slice(0, 256) } });
  }
  return span.span_id;
}

/** Load all spans for a trace, sorted by start time. */
export async function loadTrace(trace_id: string): Promise<CognitionSpan[]> {
  return __backend.loadTrace(trace_id);
}

/** For tests: reset the in-memory backend. */
export function __resetTraces(): void {
  if (__backend.__reset) __backend.__reset();
}
